def transform(input_grid: list[list[int]]) -> list[list[int]]:
    # Input is 3x3
    # Output will be 9x9
    output = [[0] * 9 for _ in range(9)]

    # For each cell in input
    for i in range(3):
        for j in range(3):
            # Determine the block position
            block_row = i
            block_col = j
            # The top-left corner of the block in output
            start_row = block_row * 3
            start_col = block_col * 3

            # If the input cell is 0, fill the 3x3 block with 0s
            if input_grid[i][j] == 0:
                for r in range(3):
                    for c in range(3):
                        output[start_row + r][start_col + c] = 0
            else:
                # Otherwise, copy the entire input grid into the block
                for r in range(3):
                    for c in range(3):
                        output[start_row + r][start_col + c] = input_grid[r][c]

    return output
